import { By } from 'selenium-webdriver';
import { DriverLike, register } from '@oracle/oraclejet-webdriver';
import { AccordionItemMultipleWebElement } from './AccordionItemMultipleWebElement';
export { AccordionItemMultipleWebElement };

/**
 * Retrieve an instance of [AccordionItemMultipleWebElement](../classes/AccordionItemMultipleWebElement.html).
 * @example
 * ```javascript
 * import { findAccordionItemMultiple } from '@oracle/oraclejet-core-pack/webdriver';
 * const el = await findAccordionItemMultiple(driver, By.id('my-oj-c-accordion-item-multiple'));
 * ```
 * @param driver A WebDriver/WebElement instance from where the element will be
 * searched. If WebDriver is passed, the element will be searched globally in the
 * document. If WebElement is passed, the search will be relative to this element.
 * @param by The locator with which to find the element
 */
export async function findAccordionItemMultiple(
  driver: DriverLike,
  by: By
): Promise<AccordionItemMultipleWebElement> {
  const webEl = await driver.findElement(by);
  // Check that the element is of type AccordionItemMultipleWebElement
  if (!(webEl instanceof AccordionItemMultipleWebElement)) {
    const tagName = await webEl.getTagName();
    let supplemental = '';
    if (webEl.constructor.name === 'AccordionItemMultipleWebElement') {
      supplemental = 'You likely have multiple installations of this package.';
    }
    throw Error(
      `findAccordionItemMultiple(${by}) created ${webEl.constructor.name} for <${tagName}>, but expected ${AccordionItemMultipleWebElement.name}. ${supplemental}`
    );
  }
  return webEl;
}

register('oj-c-accordion-item-multiple', AccordionItemMultipleWebElement);
